// ── DB Helpers ────────────────────────────────────────────────
const orderToDb = (o) => ({
  id:            o.id,
  table_num:     o.table,
  items:         o.items,
  total:         o.total,
  subtotal:      o.subtotal ?? o.total,
  discount:      o.discount ?? 0,
  status:        o.status,
  note:          o.note ?? null,
  pay:           o.pay ?? null,
  time:          o.time instanceof Date ? o.time.toISOString() : (o.time || new Date().toISOString()),
  line_user_id:  o.line_user_id ?? null,
  member_phone:  o.memberPhone ?? null,
  earned_points: o.earnedPoints ?? 0,
  points_used:   o.pointsUsed ?? 0,
});

const dbToOrder = (row) => ({
  id:           row.id,
  table:        row.table_num,
  items:        row.items || [],
  total:        row.total,
  subtotal:     row.subtotal ?? row.total,
  discount:     row.discount ?? 0,
  status:       row.status,
  note:         row.note,
  pay:          row.pay,
  time:         row.time ? new Date(row.time) : new Date(),
  line_user_id: row.line_user_id,
  memberPhone:  row.member_phone,
  earnedPoints: row.earned_points ?? 0,
  pointsUsed:   row.points_used ?? 0,
});

async function fetchTodayOrders() {
  const todayTH = new Date();
  todayTH.setHours(0, 0, 0, 0);
  const { data, error } = await sb
    .from("orders")
    .select("*")
    .gte("time", new Date(todayTH.getTime() - 7*3600000).toISOString())
    .order("time", { ascending: false });
  if (error) { console.error("fetchTodayOrders:", error); return []; }
  return (data || []).map(dbToOrder);
}

async function insertOrder(order) {
  const { data, error } = await sb.from("orders").insert([orderToDb(order)]).select().single();
  if (error) throw error;
  return dbToOrder(data);
}

async function updateOrderStatusDB(id, status) {
  const { error } = await sb.from("orders").update({ status }).eq("id", id);
  if (error) console.error("updateOrderStatus:", error);
}

function subscribeOrders(callback) {
  return sb.channel("orders-rt-" + Math.random())
    .on("postgres_changes", { event: "*", schema: "public", table: "orders" }, (payload) => {
      callback(payload.eventType, payload.eventType === "DELETE" ? payload.old : dbToOrder(payload.new));
    })
    .subscribe();
}

