// ── STATUS ────────────────────────────────────────────────────
function StatusView({ currentOrder, setView }) {
  const [order, setOrder] = useState(currentOrder);
  useEffect(() => {
    if (!currentOrder?.id) return;
    // ── Realtime: ลูกค้าเห็นสถานะอัปเดตทันทีที่ครัวเปลี่ยน ──
    const ch = subscribeOrders((evt, o) => {
      if ((evt === "UPDATE" || evt === "INSERT") && o.id === currentOrder.id) {
        setOrder(o);
      }
    });
    return () => ch.unsubscribe();
  }, [currentOrder?.id]);

  const steps = [
    {key:"pending",   label:"รอรับออเดอร์",   emoji:"📋", color:"#E8A020"},
    {key:"preparing", label:"กำลังปรุงอาหาร", emoji:"🔥", color:"#2563EB"},
    {key:"served",    label:"เสิร์ฟแล้ว",     emoji:"✅", color:"#16A34A"},
  ];
  const si = steps.findIndex(s => s.key === order?.status);
  const cur = steps[Math.max(0,si)];
  const eta = {pending:15,preparing:8,served:0};

  return (
    <div className="kfade" style={{ minHeight:"100vh", paddingBottom:32 }}>
      <div style={{ background:cur.color+"18", padding:"36px 24px 24px", textAlign:"center", borderBottom:"1px solid "+C.border }}>
        <div style={{ fontSize:72, marginBottom:8 }}>{cur.emoji}</div>
        <h2 style={{ fontFamily:"'Noto Serif Thai',serif", fontSize:24, fontWeight:900, marginBottom:4 }}>{cur.label}</h2>
        <div style={{ color:"#888", fontSize:13 }}>ออเดอร์ #{order?.id} · โต๊ะ {order?.table}</div>
        {eta[order?.status] > 0 && (
          <div style={{ marginTop:10, background:cur.color, color:"white", display:"inline-block", borderRadius:20, padding:"5px 16px", fontSize:13, fontWeight:700 }}>
            ⏱ รออีกประมาณ {eta[order?.status]} นาที
          </div>
        )}
      </div>
      <div style={{ padding:"22px 20px" }}>
        <div style={{ display:"flex", justifyContent:"center", alignItems:"center", marginBottom:28 }}>
          {steps.map((step,i) => (
            <div key={step.key} style={{ display:"flex", alignItems:"center" }}>
              <div style={{ textAlign:"center", width:78 }}>
                <div style={{ width:46, height:46, borderRadius:"50%", margin:"0 auto 6px", display:"flex", alignItems:"center", justifyContent:"center", fontSize:20, background:i<=si?step.color:C.border, transition:"all .5s" }}>
                  {i<=si ? step.emoji : <span style={{ fontSize:14, color:"#BBB" }}>○</span>}
                </div>
                <div style={{ fontSize:10, fontWeight:700, color:i<=si?step.color:"#CCC", lineHeight:1.3 }}>{step.label}</div>
              </div>
              {i < steps.length-1 && <div style={{ width:22, height:3, borderRadius:3, marginBottom:20, background:i<si?C.red:C.border, transition:"background .5s" }} />}
            </div>
          ))}
        </div>
        {order?.status === "served" && (
          <div style={{ background:"#F0FFF4", border:"2px solid #16A34A", borderRadius:20, padding:20, textAlign:"center", marginBottom:20 }}>
            <div style={{ fontSize:32, marginBottom:6 }}>🎉</div>
            <div style={{ fontSize:16, fontWeight:800, color:"#16A34A" }}>อาหารมาแล้ว! ทานให้อร่อยนะคะ</div>
            <div style={{ fontSize:13, color:"#555", marginTop:4 }}>ขอบคุณที่ใช้บริการ ขาหมูนาย ต. 🍖</div>
          </div>
        )}
        <div style={{ background:"white", borderRadius:20, overflow:"hidden", marginBottom:16 }}>
          {order?.items.map(e => (
            <div key={e.key} style={{ display:"flex", alignItems:"center", borderBottom:"1px solid #F5F0EA" }}>
              <img src={IMGS[e.item.img]} style={{ width:70, height:70, objectFit:"cover", flexShrink:0 }} alt="" />
              <div style={{ padding:"10px 12px", flex:1 }}>
                <div style={{ fontSize:13, fontWeight:700 }}>{e.item.name}</div>
                {e.opts.length>0 && <div style={{ fontSize:11, color:"#8B6B55", marginTop:2 }}>{e.opts.map(o=>o.label).join(" · ")}</div>}
                <div style={{ fontSize:12, color:"#999" }}>×{e.qty}</div>
              </div>
              <div style={{ padding:"0 14px", fontWeight:800, color:C.red, fontSize:14 }}>{e.unitPrice*e.qty}฿</div>
            </div>
          ))}
          <div style={{ padding:"12px 16px", display:"flex", justifyContent:"space-between", fontSize:16, fontWeight:900 }}>
            <span>รวม</span><span style={{ color:C.red }}>{order?.total}฿</span>
          </div>
        </div>
        {order?.note && (
          <div style={{ background:"#FFFBF0", border:"1px solid #F0D080", borderRadius:16, padding:14, marginBottom:16, fontSize:13 }}>
            <span style={{ fontWeight:700, color:"#8B6B30" }}>📝 หมายเหตุ: </span>{order.note}
          </div>
        )}
        <div style={{ display:"flex", gap:10 }}>
          <button className="kbtn" style={{ flex:1, padding:14, borderRadius:16, border:"2px solid #DDD", color:"#666", fontSize:14 }} onClick={() => setView("menu")}>+ สั่งเพิ่ม</button>
          <button className="kbtn" style={{ flex:1, padding:14, borderRadius:16, border:"2px solid #DDD", color:"#666", fontSize:14 }} onClick={() => setView("home")}>🏠 หน้าหลัก</button>
        </div>
      </div>
    </div>
  );
}

// ── HOME (Phase 2 update) ─────────────────────────────────────
// Patch HomeView to show member button - done via prop already in App routing
// We add MemberView & update CartView inline below

// ── MEMBER VIEW (Phase 2) ─────────────────────────────────────
function MemberView({ member, setMember, setView, showNotif }) {
  const [tab, setTab] = useState(member ? "profile" : "login");
  const [phone, setPhone] = useState("");
  const [name, setName] = useState("");
  const [loading, setLoading] = useState(false);

  const history = member ? getOrderHistory(member.phone) : [];
  const redeemable = member ? Math.floor(member.points / POINTS_PER_REWARD) : 0;

  const handleLogin = () => {
    if (phone.length < 9) { showNotif("กรุณากรอกเบอร์โทรให้ครบ", false); return; }
    setLoading(true);
    setTimeout(() => {
      let m = getMember(phone);
      if (!m) {
        if (!name.trim()) { showNotif("กรุณากรอกชื่อเพื่อสมัครสมาชิก", false); setLoading(false); return; }
        m = { phone, name: name.trim(), points: 0, joined: new Date().toISOString(), lastOrder: null };
        saveMember(phone, m);
        showNotif("ยินดีต้อนรับสมาชิกใหม่! 🎉", true);
      } else {
        showNotif("ยินดีต้อนรับกลับมา " + m.name + " 👋", true);
      }
      setMember(m);
      setTab("profile");
      setLoading(false);
    }, 600);
  };

  const handleLogout = () => { setMember(null); setView("home"); };

  const tierInfo = (pts) => {
    if (pts >= 5000) return { name:"Gold 🥇", color:"#F0B030", next:null, needed:0 };
    if (pts >= 2000) return { name:"Silver 🥈", color:"#AAA", next:"Gold", needed:5000-pts };
    if (pts >= 500)  return { name:"Bronze 🥉", color:"#CD7F32", next:"Silver", needed:2000-pts };
    return { name:"New Member", color:C.muted, next:"Bronze", needed:500-pts };
  };

  const tier = member ? tierInfo(member.points) : null;
  const pct = member && tier?.next ? Math.min(100, ((member.points % (tier.name==="New Member"?500:tier.name==="Bronze 🥉"?1500:3000)) / (tier.name==="New Member"?500:tier.name==="Bronze 🥉"?1500:3000)) * 100) : 100;

  return (
    <div className="kfade" style={{ minHeight:"100vh", paddingBottom:32 }}>
      {/* Header */}
      <div style={{ padding:"20px 18px 0", display:"flex", alignItems:"center", gap:12, marginBottom:20 }}>
        <button className="kbtn" style={{ background:C.border, borderRadius:12, width:38, height:38, fontSize:16, display:"flex", alignItems:"center", justifyContent:"center" }} onClick={() => setView("home")}>←</button>
        <h2 style={{ fontFamily:"'Noto Serif Thai',serif", fontSize:20, fontWeight:900 }}>👤 สมาชิก</h2>
      </div>

      {!member || tab === "login" ? (
        /* ── Login / Register ── */
        <div style={{ padding:"0 18px" }}>
          <div style={{ background:"white", borderRadius:20, padding:24, marginBottom:16 }}>
            <div style={{ textAlign:"center", marginBottom:20 }}>
              <div style={{ fontSize:56, marginBottom:8 }}>🍖</div>
              <h3 style={{ fontFamily:"'Noto Serif Thai',serif", fontSize:20, fontWeight:900, marginBottom:4 }}>สมาชิก ขาหมูนาย ต.</h3>
              <p style={{ fontSize:13, color:"#888" }}>สะสมแต้ม แลกส่วนลด ทุก 500 แต้ม = 50฿</p>
            </div>
            <div style={{ marginBottom:14 }}>
              <div style={{ fontSize:12, fontWeight:700, color:C.muted, marginBottom:6 }}>เบอร์โทรศัพท์</div>
              <input className="kinp" type="tel" placeholder="0XX-XXX-XXXX" value={phone} onChange={e=>setPhone(e.target.value.replace(/\D/g,"").slice(0,10))} />
            </div>
            {(!getMember(phone) && phone.length >= 9) && (
              <div style={{ marginBottom:14 }}>
                <div style={{ fontSize:12, fontWeight:700, color:C.muted, marginBottom:6 }}>ชื่อ (สำหรับสมาชิกใหม่)</div>
                <input className="kinp" placeholder="ชื่อ-นามสกุล" value={name} onChange={e=>setName(e.target.value)} />
              </div>
            )}
            <button className="kbtn" style={{ width:"100%", padding:16, fontSize:15, borderRadius:16, background:C.red, color:"white", opacity:loading?0.7:1, boxShadow:"0 6px 20px rgba(139,38,53,.3)" }} onClick={handleLogin} disabled={loading}>
              {loading ? "⏳ กำลังตรวจสอบ..." : phone.length>=9 && !getMember(phone) ? "✨ สมัครสมาชิก" : "🔐 เข้าสู่ระบบ"}
            </button>
          </div>
          <div style={{ background:"linear-gradient(135deg,#FFF8F0,#FFF3E8)", borderRadius:18, padding:18 }}>
            <div style={{ fontSize:13, fontWeight:800, color:C.red, marginBottom:10 }}>🎁 สิทธิพิเศษสมาชิก</div>
            {[["🏆","สะสมแต้มทุกบิล","1 บาท = 1 แต้ม"],["💰","แลกส่วนลด","ทุก 500 แต้ม = ลด 50฿"],["⭐","เลื่อนระดับ","Bronze → Silver → Gold"],["📋","ประวัติออเดอร์","ดูรายการสั่งซื้อย้อนหลัง"]].map(([i,t,d])=>(
              <div key={t} style={{ display:"flex", gap:10, alignItems:"flex-start", marginBottom:10 }}>
                <span style={{ fontSize:20 }}>{i}</span>
                <div><div style={{ fontSize:13, fontWeight:700 }}>{t}</div><div style={{ fontSize:12, color:"#888" }}>{d}</div></div>
              </div>
            ))}
          </div>
        </div>
      ) : (
        /* ── Profile ── */
        <div style={{ padding:"0 18px" }}>
          {/* Member card */}
          <div style={{ background:`linear-gradient(135deg, ${tier.color}22, ${tier.color}11)`, border:`2px solid ${tier.color}44`, borderRadius:22, padding:22, marginBottom:16 }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:16 }}>
              <div>
                <div style={{ fontSize:11, fontWeight:800, color:tier.color, letterSpacing:2, textTransform:"uppercase" }}>{tier.name}</div>
                <div style={{ fontFamily:"'Noto Serif Thai',serif", fontSize:22, fontWeight:900, color:C.dark, marginTop:2 }}>{member.name}</div>
                <div style={{ fontSize:13, color:"#888", marginTop:2 }}>📱 {member.phone}</div>
              </div>
              <div style={{ textAlign:"right" }}>
                <div style={{ fontSize:11, color:"#888" }}>แต้มสะสม</div>
                <div style={{ fontSize:32, fontWeight:900, color:C.red, lineHeight:1 }}>{member.points.toLocaleString()}</div>
                <div style={{ fontSize:11, color:"#888", marginTop:2 }}>แต้ม</div>
              </div>
            </div>
            {/* Progress bar */}
            {tier.next && (
              <div>
                <div style={{ display:"flex", justifyContent:"space-between", fontSize:11, color:"#888", marginBottom:6 }}>
                  <span>{tier.name}</span><span>อีก {tier.needed.toLocaleString()} แต้ม → {tier.next}</span>
                </div>
                <div className="pts-bar-bg"><div className="pts-bar-fill" style={{ width:pct+"%" }} /></div>
              </div>
            )}
          </div>

          {/* Points summary */}
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:12, marginBottom:16 }}>
            <div style={{ background:"white", borderRadius:18, padding:16, textAlign:"center" }}>
              <div style={{ fontSize:28, fontWeight:900, color:C.red }}>{member.points.toLocaleString()}</div>
              <div style={{ fontSize:12, color:"#888" }}>แต้มคงเหลือ</div>
            </div>
            <div style={{ background:"white", borderRadius:18, padding:16, textAlign:"center" }}>
              <div style={{ fontSize:28, fontWeight:900, color:"#16A34A" }}>{redeemable > 0 ? redeemable+"×" : "0"}</div>
              <div style={{ fontSize:12, color:"#888" }}>แลกส่วนลดได้ {redeemable*50}฿</div>
            </div>
          </div>

          {/* Redeem info */}
          {redeemable > 0 && (
            <div style={{ background:"#F0FFF4", border:"2px solid #16A34A", borderRadius:16, padding:14, marginBottom:16, display:"flex", alignItems:"center", gap:12 }}>
              <span style={{ fontSize:28 }}>🎉</span>
              <div>
                <div style={{ fontSize:14, fontWeight:800, color:"#16A34A" }}>แลกส่วนลดได้เลย!</div>
                <div style={{ fontSize:12, color:"#555" }}>มี {redeemable} ครั้ง · ครั้งละ 50฿ (ใช้ตอนชำระเงิน)</div>
              </div>
            </div>
          )}

          {/* Order history */}
          <div style={{ marginBottom:16 }}>
            <div style={{ fontSize:11, fontWeight:800, color:C.muted, textTransform:"uppercase", letterSpacing:1.5, marginBottom:12 }}>📋 ประวัติการสั่ง</div>
            {history.length === 0 ? (
              <div style={{ background:"white", borderRadius:18, padding:24, textAlign:"center", color:"#AAA" }}>
                <div style={{ fontSize:36, marginBottom:8 }}>🍽️</div><p>ยังไม่มีประวัติการสั่ง</p>
              </div>
            ) : history.slice(0,8).map((o,i) => (
              <div key={i} style={{ background:"white", borderRadius:16, padding:"14px 16px", marginBottom:10, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                <div>
                  <div style={{ fontSize:13, fontWeight:700 }}>ออเดอร์ #{o.id} · โต๊ะ {o.table}</div>
                  <div style={{ fontSize:12, color:"#888", marginTop:2 }}>{new Date(o.time).toLocaleDateString("th-TH",{day:"numeric",month:"short",year:"numeric"})}</div>
                  <div style={{ fontSize:11, color:C.muted, marginTop:2 }}>{o.items?.slice(0,2).map(e=>e.item.name).join(", ")}{o.items?.length>2?"...":""}</div>
                </div>
                <div style={{ textAlign:"right" }}>
                  <div style={{ fontSize:15, fontWeight:900, color:C.red }}>{o.total}฿</div>
                  {o.earnedPoints > 0 && <div style={{ fontSize:11, color:"#16A34A", marginTop:2 }}>+{o.earnedPoints} แต้ม</div>}
                </div>
              </div>
            ))}
          </div>

          <button className="kbtn" style={{ width:"100%", padding:14, fontSize:14, borderRadius:16, border:"2px solid #DDD", color:"#888" }} onClick={handleLogout}>
            ออกจากระบบ
          </button>
        </div>
      )}
    </div>
  );
}

// ── DELIVERY VIEW ───────────────────────────────────────────
function DeliveryView({ setView, cart, setCart, placeOrder, cartTotal, cartSubtotal, discount, member, pointsUsed, setPointsUsed, addToCart, upsell, cartCount }) {
  const [step, setStep]       = useState("menu");  // menu | address | confirm | status
  const [address, setAddress] = useState({
    name: "", place: "", phone: "", note: ""
  });
  const [deliveryTime, setDeliveryTime] = useState("morning");
  const [modal, setModal]     = useState(null);
  const [cat, setCat]         = useState("ทั้งหมด");
  const [search, setSearch]   = useState("");
  const [currentOrder, setCurrentOrder] = useState(null);

  const filtered = MENU.filter(m =>
    (cat==="ทั้งหมด" || m.cat===cat) &&
    (!search || m.name.includes(search)) &&
    !_soldOut.has(m.id)
  );

  const handlePlaceDelivery = async () => {
    const total = cart.reduce((s,e)=>s+e.unitPrice*e.qty,0);
    const order = {
      id: newOrderId(), table:"Delivery 🛵", items:[...cart], total, subtotal:total, discount:0,
      note: `🛵 Delivery\n📍 ${address.place}\n👤 ${address.name}\n📱 ${address.phone}\n⏰ ${deliveryTime==="morning"?"ช่วงเช้า 09:00":"ช่วงบ่าย 14:00"}\n📝 ${address.note}`,
      pay:"transfer", status:"pending", time:new Date(),
    };
    try {
      const saved = await insertOrder(order);
      setCurrentOrder(saved);
    } catch(err) {
      console.error("insertOrder delivery:", err);
      setCurrentOrder(order);
    }
    setCart([]);
    setStep("status");
  };

  const canProceed = address.name.trim() && address.place.trim() && address.phone.trim();

  if (step==="status") return (
    <div className="kfade" style={{ minHeight:"100vh", background:C.cream, paddingBottom:40 }}>
      <div style={{ background:"#1E3A5F", padding:"40px 24px 28px", textAlign:"center" }}>
        <div style={{ fontSize:64, marginBottom:8 }}>🛵</div>
        <h2 style={{ fontFamily:"'Noto Serif Thai',serif", fontSize:24, fontWeight:900, color:"white", marginBottom:4 }}>รับออเดอร์แล้ว!</h2>
        <div style={{ color:"rgba(255,255,255,.75)", fontSize:13 }}>ออเดอร์ Delivery #{currentOrder?.id}</div>
      </div>
      <div style={{ padding:"20px 20px" }}>
        <div style={{ background:"white", borderRadius:20, padding:18, marginBottom:14 }}>
          <div style={{ fontSize:11, fontWeight:800, color:C.muted, textTransform:"uppercase", letterSpacing:1, marginBottom:12 }}>รายละเอียดการส่ง</div>
          {[
            ["👤 ชื่อ", address.name],
            ["📍 สถานที่", address.place],
            ["📱 เบอร์โทร", address.phone],
            ["⏰ รอบส่ง", deliveryTime==="morning"?"ช่วงเช้า 09:00 น.":"ช่วงบ่าย 14:00 น."],
            ["📝 หมายเหตุ", address.note||"-"],
          ].map(([k,v])=>(
            <div key={k} style={{ display:"flex", gap:8, padding:"8px 0", borderBottom:"1px solid #F5F0EA", fontSize:14 }}>
              <span style={{ color:"#888", minWidth:90 }}>{k}</span>
              <span style={{ fontWeight:600, flex:1 }}>{v}</span>
            </div>
          ))}
        </div>

        <div style={{ background:"white", borderRadius:20, overflow:"hidden", marginBottom:14 }}>
          {currentOrder?.items.map(e=>(
            <div key={e.key} style={{ display:"flex", alignItems:"center", borderBottom:"1px solid #F5F0EA" }}>
              <img src={IMGS[e.item.img]} style={{ width:66,height:66,objectFit:"cover",flexShrink:0 }} alt="" />
              <div style={{ padding:"10px 12px", flex:1 }}>
                <div style={{ fontSize:13, fontWeight:700 }}>{e.item.name}</div>
                {e.opts.length>0 && <div style={{ fontSize:11,color:"#8B6B55",marginTop:2 }}>{e.opts.map(o=>o.label).join(" · ")}</div>}
                <div style={{ fontSize:12, color:"#999" }}>×{e.qty}</div>
              </div>
              <div style={{ padding:"0 14px",fontWeight:800,color:C.red,fontSize:14 }}>{e.unitPrice*e.qty}฿</div>
            </div>
          ))}
          <div style={{ padding:"12px 16px",display:"flex",justifyContent:"space-between",fontSize:16,fontWeight:900 }}>
            <span>รวม</span><span style={{ color:C.red }}>{currentOrder?.total}฿</span>
          </div>
        </div>

        <div style={{ background:"#FFF8F0", border:"2px solid #F0D080", borderRadius:18, padding:16, marginBottom:14, fontSize:13, lineHeight:1.7 }}>
          <div style={{ fontWeight:800, color:"#8B6B30", marginBottom:8 }}>💳 ชำระเงิน</div>
          <div style={{ textAlign:"center", marginBottom:10 }}>
            <img src={IMGS.qr_promptpay} style={{ width:180, height:"auto", borderRadius:12, border:"3px solid #F0D080", display:"inline-block" }} alt="QR PromptPay" />
            <div style={{ fontSize:11, color:"#8B6B30", marginTop:4, fontWeight:700 }}>สแกน QR จ่าย PromptPay</div>
          </div>
          <div>หรือโอนผ่านธนาคาร ไทยพาณิชย์ (SCB)</div>
          <div style={{ fontWeight:700 }}>566-542401-3 · ชนินทร์ ปิติวงษ์</div>
          <div style={{ color:"#888", marginTop:4 }}>กรุณาส่งสลิปมาที่ LINE ของร้านหลังโอน</div>
        </div>

        <div style={{ display:"flex", gap:10 }}>
          <button className="kbtn" style={{ flex:1,padding:14,borderRadius:16,border:"2px solid #DDD",color:"#666",fontSize:14 }} onClick={()=>{setStep("menu");}}>+ สั่งเพิ่ม</button>
          <button className="kbtn" style={{ flex:1,padding:14,borderRadius:16,border:"2px solid #DDD",color:"#666",fontSize:14 }} onClick={()=>setView("home")}>🏠 หน้าหลัก</button>
        </div>
      </div>
    </div>
  );

  if (step==="address") return (
    <div className="kfade" style={{ minHeight:"100vh", background:C.cream, paddingBottom:120 }}>
      <div style={{ padding:"20px 18px 16px",display:"flex",alignItems:"center",gap:12,borderBottom:"1px solid "+C.border }}>
        <button className="kbtn" style={{ background:C.border,borderRadius:12,width:38,height:38,fontSize:16,display:"flex",alignItems:"center",justifyContent:"center" }} onClick={()=>setStep("menu")}>←</button>
        <h2 style={{ fontFamily:"'Noto Serif Thai',serif",fontSize:20,fontWeight:900 }}>📍 ที่อยู่จัดส่ง</h2>
      </div>
      <div style={{ padding:"16px 18px" }}>
        {/* Delivery info banner */}
        <div style={{ background:"linear-gradient(135deg,#1E3A5F,#2563EB)", borderRadius:18, padding:16, marginBottom:16, color:"white" }}>
          <div style={{ fontSize:14, fontWeight:800, marginBottom:8 }}>🛵 ข้อมูลการจัดส่ง</div>
          <div style={{ fontSize:13, lineHeight:1.8, opacity:.9 }}>
            <div>✅ ฟรีค่าส่ง ภายใน 5 กม. ในเขตตัวเมืองเชียงราย</div>
            <div>🗺️ ไกลกว่า 5 กม. เริ่มต้นค่าส่ง 30 บาท</div>
            <div>⏰ รอบเช้า 09:00 น. | รอบบ่าย 14:00 น.</div>
          </div>
        </div>

        {/* Delivery time */}
        <div style={{ background:"white",borderRadius:18,padding:18,marginBottom:14 }}>
          <div style={{ fontSize:12,fontWeight:800,color:C.muted,textTransform:"uppercase",letterSpacing:1,marginBottom:12 }}>⏰ เลือกรอบจัดส่ง</div>
          <div style={{ display:"grid",gridTemplateColumns:"1fr 1fr",gap:10 }}>
            {[
              {id:"morning",label:"ช่วงเช้า",time:"09:00 น.",icon:"🌅"},
              {id:"afternoon",label:"ช่วงบ่าย",time:"14:00 น.",icon:"☀️"},
            ].map(t=>(
              <div key={t.id} onClick={()=>setDeliveryTime(t.id)} style={{ background:deliveryTime===t.id?"#EFF6FF":"#F5F5F5",border:"2px solid "+(deliveryTime===t.id?C.blue:"transparent"),borderRadius:14,padding:"14px 12px",textAlign:"center",cursor:"pointer",transition:"all .2s" }}>
                <div style={{ fontSize:24,marginBottom:4 }}>{t.icon}</div>
                <div style={{ fontSize:14,fontWeight:800,color:deliveryTime===t.id?C.blue:C.dark }}>{t.label}</div>
                <div style={{ fontSize:13,color:"#888",marginTop:2 }}>{t.time}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Address form */}
        <div style={{ background:"white",borderRadius:18,padding:18,marginBottom:14 }}>
          <div style={{ fontSize:12,fontWeight:800,color:C.muted,textTransform:"uppercase",letterSpacing:1,marginBottom:14 }}>📋 ข้อมูลการจัดส่ง</div>
          {[
            {key:"name",  label:"ชื่อผู้รับ *",       placeholder:"ชื่อ-นามสกุล",         type:"text"},
            {key:"phone", label:"เบอร์โทรติดต่อ *",   placeholder:"0XX-XXX-XXXX",          type:"tel"},
            {key:"place", label:"ชื่อสถานที่ / ที่อยู่ *", placeholder:"เช่น บ้านเลขที่, หมู่บ้าน, อาคาร", type:"text"},
            {key:"note",  label:"หมายเหตุเพิ่มเติม",  placeholder:"เช่น บ้านสีขาว ใกล้ 7-11", type:"text"},
          ].map(f=>(
            <div key={f.key} style={{ marginBottom:14 }}>
              <div style={{ fontSize:12,fontWeight:700,color:"#888",marginBottom:6 }}>{f.label}</div>
              <input className="kinp" type={f.type} placeholder={f.placeholder} value={address[f.key]}
                onChange={e=>setAddress(prev=>({...prev,[f.key]:e.target.value}))}
                style={{ width:"100%",background:"white",color:C.dark,border:"2px solid "+C.border }} />
            </div>
          ))}
        </div>

        {/* Google Maps link helper */}
        <div style={{ background:"#F0F4FF",border:"1px solid #C7D7F5",borderRadius:16,padding:14,marginBottom:14 }}>
          <div style={{ fontSize:12,fontWeight:700,color:C.blue,marginBottom:4 }}>🗺️ ส่ง Location ให้ง่ายขึ้น</div>
          <div style={{ fontSize:12,color:"#6B7280",lineHeight:1.6 }}>หลังสั่งแล้ว กรุณาส่ง Google Maps Location มาที่ LINE ของร้านด้วย เพื่อให้ไรเดอร์หาง่ายขึ้น</div>
        </div>

        {/* Cart summary */}
        <div style={{ background:"white",borderRadius:18,padding:16,marginBottom:14 }}>
          <div style={{ fontSize:12,fontWeight:800,color:C.muted,textTransform:"uppercase",letterSpacing:1,marginBottom:10 }}>สรุปออเดอร์ ({cart.reduce((s,e)=>s+e.qty,0)} รายการ)</div>
          {cart.map(e=>(
            <div key={e.key} style={{ display:"flex",justifyContent:"space-between",fontSize:13,padding:"5px 0",borderBottom:"1px solid #F5F0EA" }}>
              <span style={{ flex:1 }}>{e.item.name} ×{e.qty}</span>
              <span style={{ fontWeight:700 }}>{e.unitPrice*e.qty}฿</span>
            </div>
          ))}
          <div style={{ display:"flex",justifyContent:"space-between",fontSize:17,fontWeight:900,marginTop:10 }}>
            <span>รวม</span><span style={{ color:C.red }}>{cartTotal}฿</span>
          </div>
        </div>
      </div>

      <div style={{ position:"fixed",bottom:16,left:16,right:16 }}>
        <button className="kbtn" style={{ width:"100%",padding:18,fontSize:16,borderRadius:20,background:canProceed?C.red:"#AAA",color:"white",boxShadow:canProceed?"0 8px 28px rgba(139,38,53,.35)":"none",opacity:canProceed?1:0.7 }}
          onClick={canProceed?handlePlaceDelivery:undefined} disabled={!canProceed}>
          {canProceed?"✅ ยืนยันออเดอร์ Delivery":"กรุณากรอกข้อมูลให้ครบ"}
        </button>
      </div>
    </div>
  );

  // ── DELIVERY MENU STEP ──────────────────────────────────────
  return (
    <div style={{ minHeight:"100vh",paddingBottom:110,background:C.cream }}>
      {/* Header */}
      <div style={{ background:"linear-gradient(135deg,#1E3A5F,#2563EB)",padding:"18px 18px 14px",color:"white" }}>
        <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10 }}>
          <div style={{ display:"flex",alignItems:"center",gap:10 }}>
            <button className="kbtn" style={{ background:"rgba(255,255,255,.2)",borderRadius:12,width:36,height:36,fontSize:16,display:"flex",alignItems:"center",justifyContent:"center",color:"white" }} onClick={()=>setView("home")}>←</button>
            <div>
              <div style={{ fontSize:10,fontWeight:800,letterSpacing:2,opacity:.7,textTransform:"uppercase" }}>สั่งอาหาร</div>
              <div style={{ fontFamily:"'Noto Serif Thai',serif",fontSize:18,fontWeight:900 }}>🛵 Delivery</div>
            </div>
          </div>
          <button onClick={()=>{if(cart.length>0)setStep("address");}} style={{ position:"relative",background:"rgba(255,255,255,.2)",border:"none",borderRadius:"50%",width:44,height:44,cursor:"pointer",fontSize:18,display:"flex",alignItems:"center",justifyContent:"center",color:"white" }}>
            🛒
            {cartCount>0 && <span style={{ position:"absolute",top:-4,right:-4,background:C.red,color:"white",borderRadius:"50%",width:20,height:20,fontSize:11,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:800 }}>{cartCount}</span>}
          </button>
        </div>
        {/* Delivery info chips */}
        <div style={{ display:"flex",gap:8,overflowX:"auto",scrollbarWidth:"none" }}>
          {["✅ ฟรี 5 กม.","🗺️ >5 กม. = 30฿+","⏰ 09:00 | 14:00"].map(t=>(
            <span key={t} style={{ whiteSpace:"nowrap",background:"rgba(255,255,255,.15)",borderRadius:20,padding:"5px 12px",fontSize:11,fontWeight:600 }}>{t}</span>
          ))}
        </div>
      </div>

      {/* Search + cats */}
      <div style={{ background:C.cream,borderBottom:"1px solid "+C.border,padding:"10px 18px" }}>
        <input className="kinp" placeholder="🔍 ค้นหาเมนู..." value={search} onChange={e=>setSearch(e.target.value)} style={{ width:"100%",background:"white",color:C.dark,border:"2px solid "+C.border,marginBottom:10 }} />
        <div style={{ display:"flex",gap:8,overflowX:"auto",scrollbarWidth:"none" }}>
          {CATS.map(c=>(
            <button key={c} className="kbtn" style={{ padding:"7px 16px",borderRadius:20,fontSize:12,whiteSpace:"nowrap",background:cat===c?C.dark:C.border,color:cat===c?"white":"#6B5B4B" }} onClick={()=>setCat(c)}>{c}</button>
          ))}
        </div>
      </div>

      {/* Menu grid */}
      <div style={{ padding:"10px 16px",display:"grid",gridTemplateColumns:"1fr 1fr",gap:14 }}>
        {filtered.map(item=>(
          <div key={item.id} className="kcard kfade" onClick={()=>setModal(item)}>
            <div style={{ position:"relative" }}>
              <img src={IMGS[item.img]} style={{ width:"100%",height:148,objectFit:"cover" }} alt={item.name} />
              {item.badge && <span style={{ position:"absolute",top:8,left:8,background:C.red,color:"white",fontSize:10,fontWeight:800,padding:"3px 8px",borderRadius:20 }}>{item.badge}</span>}
            </div>
            <div style={{ padding:"11px 13px 13px" }}>
              <div style={{ fontSize:10,fontWeight:700,color:C.muted,textTransform:"uppercase",letterSpacing:1,marginBottom:3 }}>{item.cat}</div>
              <div style={{ fontSize:13,fontWeight:700,color:C.dark,marginBottom:4,lineHeight:1.4 }}>{item.name}</div>
              <div style={{ fontSize:11,color:"#AAA",marginBottom:10,lineHeight:1.4,overflow:"hidden",display:"-webkit-box",WebkitLineClamp:2,WebkitBoxOrient:"vertical" }}>{item.desc}</div>
              <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center" }}>
                <span style={{ fontSize:17,fontWeight:900,color:C.red }}>{item.price}฿</span>
                <button className="kbtn" style={{ background:C.red,color:"white",padding:"6px 14px",fontSize:14,borderRadius:12 }}
                  onClick={e=>{ e.stopPropagation(); item.opts.length===0?addToCart(item,[]):setModal(item); }}>+</button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {cartCount>0 && (
        <div style={{ position:"fixed",bottom:16,left:16,right:16,zIndex:30 }}>
          <button className="kbtn" style={{ width:"100%",padding:"15px 20px",fontSize:15,borderRadius:20,background:C.red,color:"white",display:"flex",justifyContent:"space-between",alignItems:"center",boxShadow:"0 8px 28px rgba(139,38,53,.4)" }} onClick={()=>setStep("address")}>
            <span style={{ background:"rgba(255,255,255,.25)",borderRadius:12,padding:"3px 12px",fontSize:13 }}>{cartCount} รายการ</span>
            <span>ระบุที่อยู่ส่ง →</span>
            <span style={{ opacity:.85,fontSize:14 }}>{cartTotal}฿</span>
          </button>
        </div>
      )}
      {upsell && <div className="ktoast" style={{ background:C.dark,color:"white" }}>💡 {upsell}</div>}
      {modal && <ItemModal item={modal} onClose={()=>setModal(null)} onAdd={opts=>{addToCart(modal,opts);setModal(null);}} />}
    </div>
  );
}

// ── KITCHEN ──────────────────────────────────────────────────
function KitchenView({ setView, updateStatus }) {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState("pending");
  const [summary, setSummary] = useState(false);
  const [soldOutMode, setSoldOutMode] = useState(false);
  const [soldOutIds, setSoldOutIds] = useState(new Set(_soldOut));

  // ── โหลดออเดอร์วันนี้ + Subscribe Realtime ──────────────────
  useEffect(() => {
    let ch;
    (async () => {
      setLoading(true);
      const today = await fetchTodayOrders();
      setOrders(today);
      setLoading(false);

      // Subscribe: ทุกเครื่องในครัวเห็นการเปลี่ยนแปลงพร้อมกัน
      ch = subscribeOrders((evt, o) => {
        setOrders(prev => {
          if (evt === "INSERT") {
            // ถ้ามีอยู่แล้ว (optimistic) ให้ merge
            return prev.find(x => x.id === o.id) ? prev : [o, ...prev];
          }
          if (evt === "UPDATE") {
            return prev.map(x => x.id === o.id ? o : x);
          }
          if (evt === "DELETE") {
            return prev.filter(x => x.id !== o.id);
          }
          return prev;
        });
      });
    })();
    return () => { if (ch) ch.unsubscribe(); };
  }, []);

  const setStatus = async (id, status) => {
    // Optimistic update ทันที แล้วค่อยบันทึก DB
    setOrders(prev => prev.map(o => o.id === id ? {...o, status} : o));
    await updateOrderStatusDB(id, status);
    // Realtime จะ broadcast ให้เครื่องอื่นอัปเดตเอง
  };

  const SC = {pending:"#E8A020",preparing:"#2563EB",served:"#16A34A"};
  const SL = {pending:"รอรับ",preparing:"กำลังทำ",served:"เสิร์ฟแล้ว"};
  const tabOrders = orders.filter(o => o.status === tab);
  const todayTotal = orders.reduce((s,o) => s+o.total, 0);
  const topItems = {};
  orders.forEach(o => o.items.forEach(e => { topItems[e.item.name]=(topItems[e.item.name]||0)+e.qty; }));
  const topList = Object.entries(topItems).sort((a,b)=>b[1]-a[1]).slice(0,5);

  return (
    <div style={{ minHeight:"100vh", background:"#0F0F0F", color:C.cream }}>
      <div style={{ background:"#1A1A1A", borderBottom:"1px solid #2A2A2A" }}>
        <div style={{ padding:"18px 18px 0", display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
          <div>
            <div style={{ fontSize:10, fontWeight:700, color:"#888", letterSpacing:2, textTransform:"uppercase" }}>Kitchen Dashboard</div>
            <h2 style={{ fontFamily:"'Noto Serif Thai',serif", fontSize:20, fontWeight:900 }}>🧑‍🍳 ขาหมูนาย ต.</h2>
          </div>
          <div style={{ textAlign:"right" }}>
            <div style={{ fontSize:10, color:"#888" }}>ยอดวันนี้</div>
            <div style={{ fontSize:22, fontWeight:900, color:C.gold }}>{todayTotal.toLocaleString()}฿</div>
          </div>
        </div>
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr 1fr", gap:8, padding:"0 18px 14px" }}>
          {[["รอรับ","pending","#E8A020"],["กำลังทำ","preparing","#2563EB"],["เสิร์ฟแล้ว","served","#16A34A"],["ทั้งหมด","all","#8B2635"]].map(([l,k,col]) => (
            <div key={k} style={{ background:"#252525", borderRadius:12, padding:"10px 6px", textAlign:"center", borderTop:"3px solid "+col }}>
              <div style={{ fontSize:22, fontWeight:900, color:col }}>{k==="all"?orders.length:orders.filter(o=>o.status===k).length}</div>
              <div style={{ fontSize:9, color:"#777" }}>{l}</div>
            </div>
          ))}
        </div>
        <div style={{ display:"flex" }}>
          {["pending","preparing","served"].map(t => (
            <button key={t} className="kbtn" style={{ flex:1, padding:"10px 4px", background:"transparent", color:tab===t?"white":"#666", fontSize:12, borderBottom:"3px solid "+(tab===t?SC[t]:"transparent") }} onClick={() => setTab(t)}>
              {SL[t]} ({orders.filter(o=>o.status===t).length})
            </button>
          ))}
        </div>
      </div>

      <div style={{ padding:16, paddingBottom:88 }}>
        {loading ? (
          <div style={{ textAlign:"center", padding:"60px 24px", color:"#555" }}>
            <div style={{ fontSize:40, marginBottom:12 }}>⏳</div>
            <p style={{ fontSize:14 }}>กำลังโหลดออเดอร์จาก Supabase...</p>
            <div style={{ width:40, height:3, background:"#E8A020", borderRadius:3, margin:"16px auto 0", animation:"kf 1s ease infinite" }} />
          </div>
        ) : tabOrders.length === 0 ? (
          <div style={{ textAlign:"center", padding:"50px 24px", color:"#444" }}>
            <div style={{ fontSize:48, marginBottom:12 }}>{tab==="pending"?"⏳":tab==="preparing"?"🔥":"✅"}</div>
            <p>{tab==="served"?"ยังไม่มีออเดอร์ที่เสิร์ฟแล้ว":tab==="preparing"?"ไม่มีออเดอร์กำลังทำ":"ไม่มีออเดอร์รออยู่"}</p>
            {tab==="pending" && <p style={{ fontSize:12, marginTop:8, color:"#555" }}>ลองสั่งจากหน้าลูกค้าก่อนนะคะ 🍖</p>}
          </div>
        ) : tabOrders.map(order => (
          <div key={order.id} className="kfade" style={{ background:"#1A1A1A", borderRadius:18, marginBottom:14, overflow:"hidden", borderLeft:"4px solid "+SC[order.status] }}>
            <div style={{ padding:"14px 16px 10px", display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
              <div>
                <div style={{ fontWeight:800, fontSize:16 }}>ออเดอร์ #{order.id}</div>
                <div style={{ fontSize:12, color:"#888", marginTop:2 }}>โต๊ะ {order.table} · {order.time?.toLocaleTimeString("th-TH",{hour:"2-digit",minute:"2-digit"})}</div>
                {order.pay && <div style={{ fontSize:11, color:"#666", marginTop:1 }}>💳 {order.pay==="cash"?"เงินสด":order.pay==="promptpay"?"PromptPay":"โอนธนาคาร"}</div>}
              </div>
              <span style={{ background:SC[order.status]+"22", color:SC[order.status], fontSize:11, fontWeight:800, padding:"5px 12px", borderRadius:20 }}>{SL[order.status]}</span>
            </div>
            <div style={{ display:"flex", gap:6, padding:"0 16px 12px", overflowX:"auto", scrollbarWidth:"none" }}>
              {order.items.map(e => (
                <div key={e.key} style={{ flexShrink:0, position:"relative" }}>
                  <img src={IMGS[e.item.img]} style={{ width:60, height:60, objectFit:"cover", borderRadius:12, border:"1px solid #2A2A2A" }} alt="" />
                  <div style={{ position:"absolute", bottom:2, right:2, background:"rgba(0,0,0,.75)", color:"white", fontSize:10, fontWeight:800, padding:"1px 5px", borderRadius:6 }}>×{e.qty}</div>
                </div>
              ))}
            </div>
            <div style={{ padding:"0 16px 12px" }}>
              {order.items.map(e => (
                <div key={e.key} style={{ fontSize:13, color:"#CCC", marginBottom:3 }}>
                  • {e.item.name} ×{e.qty}
                  {e.opts.length>0 && <span style={{ color:C.gold, fontSize:12 }}> ({e.opts.map(o=>o.label).join(",")})</span>}
                </div>
              ))}
              {order.note && <div style={{ marginTop:8, fontSize:12, color:C.gold }}>📝 {order.note}</div>}
            </div>
            <div style={{ padding:"10px 16px 14px", display:"flex", justifyContent:"space-between", alignItems:"center", borderTop:"1px solid #2A2A2A" }}>
              <div style={{ fontWeight:900, color:C.gold, fontSize:16 }}>{order.total}฿</div>
              {order.status==="pending" && (
                <button className="kbtn" style={{ background:"#2563EB", color:"white", padding:"9px 18px", borderRadius:12, fontSize:13, boxShadow:"0 4px 12px rgba(37,99,235,.4)" }} onClick={() => setStatus(order.id,"preparing")}>🔥 รับออเดอร์</button>
              )}
              {order.status==="preparing" && (
                <button className="kbtn" style={{ background:"#16A34A", color:"white", padding:"9px 18px", borderRadius:12, fontSize:13, boxShadow:"0 4px 12px rgba(22,163,74,.4)" }} onClick={() => setStatus(order.id,"served")}>✅ เสิร์ฟแล้ว</button>
              )}
              {order.status==="served" && <span style={{ fontSize:12, color:"#16A34A", fontWeight:700 }}>เสร็จสิ้น ✓</span>}
            </div>
          </div>
        ))}
      </div>

      {/* Sold-out toggle modal */}
      {soldOutMode && (
        <div style={{ position:"fixed", inset:0, zIndex:100 }}>
          <div onClick={()=>setSoldOutMode(false)} style={{ position:"absolute", inset:0, background:"rgba(0,0,0,.7)" }} />
          <div className="kslide" style={{ position:"absolute", bottom:0, left:0, right:0, background:"#1A1A1A", borderRadius:"24px 24px 0 0", padding:24, maxHeight:"80vh", overflowY:"auto" }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
              <h3 style={{ fontFamily:"'Noto Serif Thai',serif", fontSize:18, fontWeight:900 }}>🚫 จัดการเมนูหมด</h3>
              <button className="kbtn" style={{ background:"#252525", color:C.cream, width:34, height:34, borderRadius:10, fontSize:18, display:"flex", alignItems:"center", justifyContent:"center" }} onClick={()=>setSoldOutMode(false)}>×</button>
            </div>
            <p style={{ fontSize:12, color:"#666", marginBottom:16 }}>แตะเมนูที่ต้องการปิด/เปิด • ลูกค้าจะเห็นว่า "หมดแล้ว"</p>
            {MENU.map(item => {
              const isSoldOut = soldOutIds.has(item.id);
              return (
                <div key={item.id} onClick={()=>{
                  const next = new Set(soldOutIds);
                  isSoldOut ? next.delete(item.id) : next.add(item.id);
                  setSoldOutIds(next);
                  if(isSoldOut) _soldOut.delete(item.id); else _soldOut.add(item.id);
                }} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"12px 0", borderBottom:"1px solid #252525", cursor:"pointer" }}>
                  <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                    <img src={IMGS[item.img]} style={{ width:44, height:44, objectFit:"cover", borderRadius:10, filter:isSoldOut?"grayscale(100%)":"none" }} alt="" />
                    <div>
                      <div style={{ fontSize:14, fontWeight:600, color:isSoldOut?"#555":"#FAF7F2" }}>{item.name}</div>
                      <div style={{ fontSize:11, color:"#555" }}>{item.cat} · {item.price}฿</div>
                    </div>
                  </div>
                  <div style={{ padding:"5px 14px", borderRadius:20, fontSize:12, fontWeight:800, background:isSoldOut?"#3A0A0A":"#0A2A0A", color:isSoldOut?"#FF6B6B":"#4ADE80" }}>
                    {isSoldOut?"หมด":"มีสินค้า"}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      <div style={{ position:"fixed", bottom:0, left:0, right:0, maxWidth:480, margin:"0 auto", background:"#1A1A1A", borderTop:"1px solid #2A2A2A", padding:"10px 16px", display:"flex", gap:8 }}>
        <button className="kbtn" style={{ flex:1, background:"#252525", color:C.cream, padding:12, borderRadius:14, fontSize:12 }} onClick={() => setSummary(true)}>📊 ยอดขาย</button>
        <button className="kbtn" style={{ flex:1, background:"#3A1A0A", color:"#FF9966", padding:12, borderRadius:14, fontSize:12, border:"1px solid #5A2A0A" }} onClick={() => setSoldOutMode(true)}>🚫 หมดสต็อก</button>
        <button className="kbtn" style={{ flex:1, background:C.red, color:"white", padding:12, borderRadius:14, fontSize:12 }} onClick={() => setView("home")}>← ลูกค้า</button>
      </div>

      {summary && (
        <div style={{ position:"fixed", inset:0, zIndex:100 }}>
          <div onClick={() => setSummary(false)} style={{ position:"absolute", inset:0, background:"rgba(0,0,0,.7)" }} />
          <div className="kslide" style={{ position:"absolute", bottom:0, left:0, right:0, background:"#1A1A1A", borderRadius:"24px 24px 0 0", padding:24, maxHeight:"70vh", overflowY:"auto" }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:20 }}>
              <h3 style={{ fontFamily:"'Noto Serif Thai',serif", fontSize:20, fontWeight:900 }}>📊 สรุปยอดขายวันนี้</h3>
              <button className="kbtn" style={{ background:"#252525", color:C.cream, width:34, height:34, borderRadius:10, fontSize:18, display:"flex", alignItems:"center", justifyContent:"center" }} onClick={() => setSummary(false)}>×</button>
            </div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:12, marginBottom:20 }}>
              {[
                ["ยอดรวม",todayTotal.toLocaleString()+"฿",C.gold],
                ["จำนวนออเดอร์",orders.length+" รายการ","#2563EB"],
                ["เฉลี่ย/บิล",(orders.length?Math.round(todayTotal/orders.length):0)+"฿","#16A34A"],
                ["รอดำเนินการ",orders.filter(o=>o.status!=="served").length+" ออเดอร์","#E8A020"],
              ].map(([l,v,col]) => (
                <div key={l} style={{ background:"#252525", borderRadius:14, padding:16, textAlign:"center" }}>
                  <div style={{ fontSize:20, fontWeight:900, color:col, marginBottom:4 }}>{v}</div>
                  <div style={{ fontSize:11, color:"#666" }}>{l}</div>
                </div>
              ))}
            </div>
            {topList.length > 0 && (
              <div>
                <div style={{ fontSize:11, fontWeight:800, color:"#888", textTransform:"uppercase", letterSpacing:1.5, marginBottom:12 }}>🏆 เมนูขายดีวันนี้</div>
                {topList.map(([name,qty],i) => (
                  <div key={name} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"10px 0", borderBottom:"1px solid #252525" }}>
                    <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                      <span style={{ fontSize:14, fontWeight:900, color:[C.gold,"#AAA","#CD7F32","#888","#666"][i], minWidth:22 }}>#{i+1}</span>
                      <span style={{ fontSize:14 }}>{name}</span>
                    </div>
                    <span style={{ fontSize:14, fontWeight:800 }}>{qty} จาน</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
